import React, { useEffect, useState } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authEndpoint = 'https://authorization-server.com/oauth/authorize';
const tokenEndpoint = 'https://authorization-server.com/oauth/token';
const scope = 'YOUR_SCOPE';

const App = () => {
    const [authCode, setAuthCode] = useState(null);
    const [accessToken, setAccessToken] = useState(localStorage.getItem('accessToken'));

    useEffect(() => {
        const queryParams = new URLSearchParams(window.location.search);
        const code = queryParams.get('code');
        if (code) {
            setAuthCode(code);
            exchangeCodeForToken(code);
        }
    }, []);

    const handleLogin = () => {
        const authUrl = `${authEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${scope}`;
        window.location.href = authUrl;
    };

    const exchangeCodeForToken = async (code) => {
        const body = new URLSearchParams({
            grant_type: 'authorization_code',
            code: code,
            redirect_uri: redirectUri,
            client_id: clientId,
        });

        try {
            const response = await fetch(tokenEndpoint, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded',
                },
                body: body.toString(),
            });
            const data = await response.json();
            if (data.access_token) {
                localStorage.setItem('accessToken', data.access_token);
                setAccessToken(data.access_token);
            }
        } catch (error) {
            console.error('Error exchanging code for token:', error);
        }
    };

    const makeApiRequest = async () => {
        if (!accessToken) return;

        try {
            const response = await fetch('https://api.example.com/your/endpoint', {
                method: 'GET',
                headers: {
                    Authorization: `Bearer ${accessToken}`,
                    'Content-Type': 'application/json',
                },
            });
            const data = await response.json();
            console.log(data);
        } catch (error) {
            console.error('Error making API request:', error);
        }
    };

    return (
        <div>
            {accessToken ? (
                <div>
                    <h1>Welcome!</h1>
                    <button onClick={makeApiRequest}>Make API Request</button>
                </div>
            ) : (
                <button onClick={handleLogin}>Login with OAuth</button>
            )}
        </div>
    );
};

export default App;